import{_ as t,I as a,c as l,o as p,a4 as d,J as n}from"./chunks/framework.BR-X7tCu.js";const b=JSON.parse('{"title":"插件机制原理","description":"","frontmatter":{},"headers":[],"relativePath":"docs/development/plugin_develop/guide/mechanism.md","filePath":"docs/development/plugin_develop/guide/mechanism.md","lastUpdated":1781967230000}'),o={name:"docs/development/plugin_develop/guide/mechanism.md"};function h(r,s,c,k,g,m){const i=a("NolebaseGitContributors"),e=a("NolebaseGitChangelog");return p(),l("div",null,[s[0]||(s[0]=d(`<h1 id="插件机制原理" tabindex="-1">插件机制原理 <a class="header-anchor" href="#插件机制原理" aria-label="Permalink to “插件机制原理”">​</a></h1><p>在开始开发 Neo-MoFox 插件之前，了解插件系统的运作机制有助于做出更合理的设计决策。</p><h2 id="插件是什么" tabindex="-1">插件是什么？ <a class="header-anchor" href="#插件是什么" aria-label="Permalink to “插件是什么？”">​</a></h2><p>Neo-MoFox 插件本质上是一个 <strong>Python 包（目录或压缩包）</strong>，它被插件加载器发现后，通过声明式组件类与框架进行交互。</p><p>插件的工作方式可以概括为：</p><blockquote><p><strong>框架扫描插件目录 → 读取 <code>manifest.json</code> → 导入 <code>plugin.py</code> → 注册所有组件 → 插件开始工作</strong></p></blockquote><h2 id="核心架构" tabindex="-1">核心架构 <a class="header-anchor" href="#核心架构" aria-label="Permalink to “核心架构”">​</a></h2><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>┌────────────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│                      消息到来                               │</span></span>
<span class="line"><span>│                         ↓                                   │</span></span>
<span class="line"><span>│  Adapter（接收平台消息）                                     │</span></span>
<span class="line"><span>│       ↓                                                      │</span></span>
<span class="line"><span>│  EventHandler（事件预处理，可拦截）                          │</span></span>
<span class="line"><span>│       ↓                                                      │</span></span>
<span class="line"><span>│  Command（匹配命令前缀，优先路由）                           │</span></span>
<span class="line"><span>│       ↓                                                      │</span></span>
<span class="line"><span>│  Chatter（AI 对话核心，编排 Action/Tool）                    │</span></span>
<span class="line"><span>│     ├── Action（LLM 调用：发消息、发表情等）                  │</span></span>
<span class="line"><span>│     └── Tool（LLM 查询：计算、翻译、数据库等）               │</span></span>
<span class="line"><span>└────────────────────────────────────────────────────────────┘</span></span></code></pre></div><h2 id="组件签名系统" tabindex="-1">组件签名系统 <a class="header-anchor" href="#组件签名系统" aria-label="Permalink to “组件签名系统”">​</a></h2><p>每个组件都有唯一的<strong>签名（Signature）</strong>，格式为：</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>plugin_name:component_type:component_name</span></span></code></pre></div><p>例如：</p><ul><li><code>onebot_adapter:adapter:onebot_adapter</code></li><li><code>my_plugin:action:send_emoji</code></li><li><code>my_plugin:tool:calculator</code></li><li><code>my_plugin:command:help</code></li></ul><p>签名是组件依赖声明、跨插件调用的核心机制。</p><h2 id="插件加载流程" tabindex="-1">插件加载流程 <a class="header-anchor" href="#插件加载流程" aria-label="Permalink to “插件加载流程”">​</a></h2><pre class="mermaid">flowchart TD
    A[扫描 plugins/ 目录] --&gt; B[读取 manifest.json]
    B --&gt; C{依赖检查}
    C --&gt;|依赖满足| D[拓扑排序计算加载顺序]
    C --&gt;|依赖缺失| E[跳过/报错]
    D --&gt; F[导入 plugin.py]
    F --&gt; G[执行 @register_plugin 注册]
    G --&gt; H[PluginManager 加载各组件]
    H --&gt; I[注入 _plugin_ 属性]
    I --&gt; J[调用 on_plugin_loaded 钩子]
    J --&gt; K[插件就绪]</pre><h3 id="加载顺序" tabindex="-1">加载顺序 <a class="header-anchor" href="#加载顺序" aria-label="Permalink to “加载顺序”">​</a></h3><p>插件加载器会根据 <code>manifest.json</code> 中声明的 <code>dependencies.plugins</code> 进行拓扑排序，确保被依赖的插件先于依赖方加载。</p><h2 id="组件类型详解" tabindex="-1">组件类型详解 <a class="header-anchor" href="#组件类型详解" aria-label="Permalink to “组件类型详解”">​</a></h2><h3 id="消息处理链" tabindex="-1">消息处理链 <a class="header-anchor" href="#消息处理链" aria-label="Permalink to “消息处理链”">​</a></h3><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>用户消息</span></span>
<span class="line"><span>   │</span></span>
<span class="line"><span>   ▼</span></span>
<span class="line"><span>EventHandler（权重由高到低依序执行）</span></span>
<span class="line"><span>   │ 可选拦截 →（后续处理器跳过）</span></span>
<span class="line"><span>   ▼</span></span>
<span class="line"><span>Command（前缀匹配）</span></span>
<span class="line"><span>   │ 匹配成功 → 直接交给对应 Command 处理，不进入 Chatter</span></span>
<span class="line"><span>   ▼</span></span>
<span class="line"><span>Chatter（AI 对话，生成器模式）</span></span>
<span class="line"><span>   │</span></span>
<span class="line"><span>   ├── 调用 Action（由 get_llm_usables/modify_llm_usables 选出）</span></span>
<span class="line"><span>   │       └── 执行 execute() → (bool, str)</span></span>
<span class="line"><span>   └── 调用 Tool（由 get_llm_usables/modify_llm_usables 选出）</span></span>
<span class="line"><span>           └── 执行 execute() → (bool, str | dict)</span></span></code></pre></div><h3 id="llm-工具注册机制" tabindex="-1">LLM 工具注册机制 <a class="header-anchor" href="#llm-工具注册机制" aria-label="Permalink to “LLM 工具注册机制”">​</a></h3><p>Action 和 Tool 都实现了 <code>LLMUsable</code> 接口。框架会：</p><ol><li>解析 <code>execute()</code> 方法的参数签名（类型注解 + Annotated 描述）</li><li>自动生成 JSON Schema，注册为 LLM 的可调用工具</li><li>LLM 返回 Tool Call → 框架路由到对应组件执行</li></ol><div class="language-python"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">class</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> SendText</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">BaseAction</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">):</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    action_name </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;send_text&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    action_description </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;向用户发送文本消息&quot;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    async</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> def</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> execute</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">        self,</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">        content: Annotated[</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">str</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;要发送的文本内容&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">],</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    ) -&gt; tuple[</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">bool</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">str</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]:</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">        # 框架自动为 content 参数生成 LLM 可读的 Schema</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">        ...</span></span></code></pre></div><h2 id="插件-api-访问方式" tabindex="-1">插件 API 访问方式 <a class="header-anchor" href="#插件-api-访问方式" aria-label="Permalink to “插件 API 访问方式”">​</a></h2><p>插件通过 <code>src/app/plugin_system/api/</code> 下的扁平化 API 访问框架能力：</p><table tabindex="0"><thead><tr><th>模块</th><th>导入路径</th><th>用途</th></tr></thead><tbody><tr><td>日志</td><td><code>from src.app.plugin_system.api.log_api import get_logger</code></td><td>结构化日志输出</td></tr><tr><td>LLM</td><td><code>from src.app.plugin_system.api.llm_api import create_llm_request</code></td><td>调用 LLM</td></tr><tr><td>发送消息</td><td><code>from src.app.plugin_system.api.send_api import send_text</code></td><td>主动发消息</td></tr><tr><td>事件</td><td><code>from src.app.plugin_system.api.event_api import publish_event</code></td><td>发布/订阅事件</td></tr><tr><td>数据库</td><td><code>from src.app.plugin_system.api.database_api import get_by_id</code></td><td>数据库 CRUD</td></tr><tr><td>消息查询</td><td><code>from src.app.plugin_system.api.message_api import ...</code></td><td>历史消息查询</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">推荐做法</p><p>始终通过插件系统 API（<code>src/app/plugin_system/api/</code>）访问框架能力，而不是直接调用 kernel/core 内部模块。这样可以保持代码稳定，不受内部重构影响。</p></div>`,29)),n(i),n(e)])}const _=t(o,[["render",h]]);export{b as __pageData,_ as default};
